def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    if not unvisited_customers:
        return None  # All customers are visited

    best_node = None
    lowest_cost = float('inf')

    # Evaluate traffic by determining proximity of other trucks to each customer
    truck_proximity = np.zeros(len(unvisited_customers))
    for i, customer in enumerate(unvisited_customers):
        for truck_pos in all_truck_pos:
            truck_distance = calculate_distance(truck_pos, customer)
            truck_proximity[i] += np.exp(-truck_distance / 100)  # decay factor for proximity importance

    for idx, customer_pos in enumerate(unvisited_customers):
        dist_to_customer = calculate_distance(cur_truck_pos, customer_pos)
        travel_time = dist_to_customer / truck_speed
        projected_arrival = current_time + travel_time

        start_window, end_window = time_windows[idx]

        # Time window cost
        if projected_arrival < start_window:
            wait_time = start_window - projected_arrival
            total_time = travel_time + wait_time
        elif projected_arrival > end_window:
            delay_penalty = (projected_arrival - end_window) ** 2
            total_time = travel_time + delay_penalty
        else:
            total_time = travel_time

        # Crowding cost to avoid sending multiple trucks to the same region unless necessary
        crowding_cost = truck_proximity[idx] * 25  # Increase factor to amplify the effect of crowding

        # Cost function incorporating travel and delay times, along with crowding costs
        cost = total_time + crowding_cost

        if cost < lowest_cost:
            best_node = idx
            lowest_cost = cost

