def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    best_node = None
    highest_utility = -float('inf')

    # Strategy prioritizing time window closeness, but penalized by deviation from the route back to depot
    def utility_score(distance, travel_time, arrival_time, start_window, end_window, distance_to_depot, num_customers_left):
        if arrival_time < start_window:
            waiting_penalty = start_window - arrival_time
        elif arrival_time > end_window:
            waiting_penalty = (end_window - arrival_time) ** 2
        else:
            waiting_penalty = 0

        # The smaller the number of customers left, the more we should worry about getting back to the depot
        return -waiting_penalty - travel_time - distance_to_depot / (num_customers_left + 1)

    num_customers_left = len(unvisited_customers)

    for idx, customer_pos in enumerate(unvisited_customers):
        distance = calculate_distance(cur_truck_pos, customer_pos)
        travel_time = distance / truck_speed
        arrival_time = current_time + travel_time

        start_window, end_window = time_windows[idx]

        # Calculate distance back to depot from this customer
        distance_to_depot = calculate_distance(customer_pos, depot_pos)

        score = utility_score(distance, travel_time, arrival_time, start_window, end_window, distance_to_depot, num_customers_left)

        if score > highest_utility:
            highest_utility = score
            best_node = idx

    return best_node

