            time_penalty = 0

        # Congestion calculation
        local_congestion = 0
        for truck_pos in all_truck_pos:
            local_congestion += calculate_distance(customer_pos, truck_pos)
        congestion_metric = 1 / (local_congestion + 1)  # Avoid division by zero

        # Total cost calculation incorporating proximity and urgency
        cost_efficiency_ratio = (travel_time + time_penalty) * congestion_metric

        # Choose the node with the lowest cost_efficiency_ratio
        if cost_efficiency_ratio < best_score:
